23	func benchmarkPaths(t *testing.T) (repoRoot, benchmarkScript, benchDir string) {
24		t.Helper()
25		repoRoot = getRepoRoot(t)
26		benchmarkScript = filepath.Join(repoRoot, "scripts", "benchmark", "benchmark")
27		benchDir = filepath.Join(repoRoot, "scripts", "benchmark")
28		if _, err := os.Stat(benchmarkScript); err != nil {
29			t.Fatalf("benchmark script not found: %v", err)
30		}
31		return repoRoot, benchmarkScript, benchDir
32	}
