34	func writeFile(t *testing.T, path, content string) {
35		t.Helper()
36		if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil {
37			t.Fatalf("mkdir %s: %v", filepath.Dir(path), err)
38		}
39		if err := os.WriteFile(path, []byte(content), 0o755); err != nil {
40			t.Fatalf("write %s: %v", path, err)
41		}
42	}
