44	func benchmarkEnv(overrides map[string]string) []string {
45		env := make(map[string]string, len(overrides)+len(os.Environ()))
46		for _, kv := range os.Environ() {
47			key, value, ok := strings.Cut(kv, "=")
48			if !ok {
49				continue
50			}
51			env[key] = value
52		}
53		for key, value := range overrides {
54			env[key] = value
55		}
56		keys := make([]string, 0, len(env))
57		for key := range env {
58			keys = append(keys, key)
59		}
60		sort.Strings(keys)
61		out := make([]string, 0, len(keys))
62		for _, key := range keys {
63			out = append(out, key+"="+env[key])
64		}
65		return out
66	}
