68	func runBenchmark(t *testing.T, benchmarkScript, benchDir string, args []string, env map[string]string) (string, string, error) {
69		t.Helper()
70		cmd := exec.Command(benchmarkScript, args...)
71		cmd.Dir = benchDir
72		cmd.Env = benchmarkEnv(env)
73		var stdout, stderr bytes.Buffer
74		cmd.Stdout = &stdout
75		cmd.Stderr = &stderr
76		err := cmd.Run()
77		return stdout.String(), stderr.String(), err
78	}
