80	func parsePlanRow(t *testing.T, line string) map[string]string {
81		t.Helper()
82		row := make(map[string]string)
83		for _, field := range strings.Split(line, "\t") {
84			key, value, ok := strings.Cut(field, "=")
85			if !ok {
86				t.Fatalf("plan field not in key=value format: %s", field)
87			}
88			row[key] = value
89		}
90		return row
91	}
