227	// TestBenchmarkPlanMatrixExpansion verifies --plan output for profile×task×rep
228	// expansion is deterministic and pure.
229	func TestBenchmarkPlanMatrixExpansion(t *testing.T) {
230		_, benchmarkScript, benchDir := benchmarkPaths(t)
231	
232		outDir := filepath.Join(t.TempDir(), "plan-out")
233		stdout, stderr, err := runBenchmark(t, benchmarkScript, benchDir,
234			[]string{"--profile", "claude-sonnet-4-6", "--bench-set", "tb-2-1-canary", "--plan", "--out", outDir},
235			nil)
236		if err != nil {
237			t.Fatalf("command failed: %v\nstderr: %s", err, stderr)
238		}
239		if _, err := os.Stat(outDir); !os.IsNotExist(err) {
240			t.Fatalf("--plan should not create %s, but stat returned %v", outDir, err)
241		}
242	
243		lines := strings.Split(strings.TrimSpace(stdout), "\n")
244		if len(lines) != 9 {
245			t.Fatalf("expected 9 plan rows, got %d\noutput: %s", len(lines), stdout)
246		}
247	
248		expectedTasks := []string{
249			"cancel-async-tasks",
250			"log-summary-date-ranges",
251			"configure-git-webserver",
252		}
253		expectedRepSequence := []string{"1/3", "2/3", "3/3"}
254	
255		for idx, line := range lines {
256			row := parsePlanRow(t, line)
257			if row["profile"] != "claude-sonnet-4-6" {
258				t.Fatalf("row %d profile mismatch: %q", idx, row["profile"])
259			}
260			if row["bench_set"] != "tb-2-1-canary" {
261				t.Fatalf("row %d bench_set mismatch: %q", idx, row["bench_set"])
262			}
263			if row["framework"] != "terminal-bench" {
264				t.Fatalf("row %d framework mismatch: %q", idx, row["framework"])
265			}
266			if row["dataset"] != "terminal-bench-2-1" {
267				t.Fatalf("row %d dataset mismatch: %q", idx, row["dataset"])
268			}
269			if row["task_executor"] != "harbor" {
270				t.Fatalf("row %d task_executor mismatch: %q", idx, row["task_executor"])
271			}
272			taskIndex := idx / len(expectedRepSequence)
273			repIndex := idx % len(expectedRepSequence)
274			if row["task"] != expectedTasks[taskIndex] {
275				t.Fatalf("row %d task mismatch: want %q got %q", idx, expectedTasks[taskIndex], row["task"])
276			}
277			if row["rep"] != expectedRepSequence[repIndex] {
278				t.Fatalf("row %d rep mismatch: want %q got %q", idx, expectedRepSequence[repIndex], row["rep"])
279			}
280		}
281	}
