299	framework: terminal-bench
300	dataset: terminal-bench-2-1
301	default_reps: 2
302	task_executor: custom-executor
303	tasks_from: includes/tasks.yaml
304	tasks:
305	  - inline-gamma
306	  - inline-delta
307	`)
308	
309		stdout, stderr, err := runBenchmark(t, benchmarkScript, filepath.Join(getRepoRoot(t), "scripts", "benchmark"),
310			[]string{"--profile", "mini", "--bench-set", "combo", "--plan"},
