321			t.Fatalf("expected 8 plan rows, got %d\noutput: %s", len(lines), stdout)
322		}
323	
324		expectedTasks := []string{"from-alpha", "from-beta", "inline-gamma", "inline-delta"}
325		for idx, line := range lines {
326			row := parsePlanRow(t, line)
327			if row["task_executor"] != "custom-executor" {
