329			}
330			if row["task"] != expectedTasks[idx/2] {
331				t.Fatalf("row %d task mismatch: want %q got %q", idx, expectedTasks[idx/2], row["task"])
332			}
333			if row["rep"] != []string{"1/2", "2/2"}[idx%2] {
334				t.Fatalf("row %d rep mismatch: %q", idx, row["rep"])
335			}
