387	// TestHarborTaskExecutorSmoke verifies scripts/benchmark/task-executors/harbor
388	// runs end-to-end with a fixture spec and produces well-formed result.json.
389	func TestHarborTaskExecutorSmoke(t *testing.T) {
390		repoRoot := getRepoRoot(t)
391		harborExecutor := filepath.Join(repoRoot, "scripts", "benchmark", "task-executors", "harbor")
392	
393		if _, err := os.Stat(harborExecutor); err != nil {
394			t.Fatalf("harbor executor not found: %v", err)
395		}
396	
397		// Check if docker is available
398		if _, err := exec.LookPath("docker"); err != nil {
399			t.Skip("docker not available")
400		}
401	
402		tmpDir := t.TempDir()
403		cellDir := filepath.Join(tmpDir, "cell")
404		tasksDir := filepath.Join(tmpDir, "tasks")
405	
406		if err := os.MkdirAll(cellDir, 0755); err != nil {
407			t.Fatalf("failed to create cell dir: %v", err)
408		}
409		if err := os.MkdirAll(tasksDir, 0755); err != nil {
410			t.Fatalf("failed to create tasks dir: %v", err)
411		}
412	
413		taskSpec := map[string]interface{}{
414			"task_id":       "test-task",
415			"tasks_dir":     tasksDir,
416			"cell_dir":      cellDir,
417			"harbor_plugin": "scripts.benchmark.harbor_agent:FizeauAgent",
418			"image":         "fizeau-harbor-runner:latest",
419		}
420	
421		specJSON, err := json.Marshal(taskSpec)
422		if err != nil {
423			t.Fatalf("failed to marshal task spec: %v", err)
424		}
425	
426		cmd := exec.Command(harborExecutor)
427		cmd.Stdin = strings.NewReader(string(specJSON))
428		cmd.Dir = filepath.Join(repoRoot, "scripts", "benchmark")
429		cmd.Env = append(os.Environ(), "HARBOR_TASK_EXECUTOR_DRY_RUN=1")
430	
431		var stdout, stderr bytes.Buffer
432		cmd.Stdout = &stdout
433		cmd.Stderr = &stderr
434	
435		err = cmd.Run()
436		if err != nil {
437			t.Logf("executor stderr: %s", stderr.String())
438			t.Fatalf("executor failed: %v", err)
439		}
440	
441		resultPath := filepath.Join(cellDir, "result.json")
442		resultData, err := os.ReadFile(resultPath)
443		if err != nil {
444			t.Fatalf("result.json not found: %v", err)
445		}
446	
447		var result map[string]interface{}
448		if err := json.Unmarshal(resultData, &result); err != nil {
449			t.Fatalf("result.json is not valid JSON: %v", err)
450		}
451	
452		if _, ok := result["dry_run"]; !ok {
453			t.Errorf("result.json missing 'dry_run' field")
454		}
455		if taskID, ok := result["task_id"]; !ok || taskID != "test-task" {
456			t.Errorf("result.json task_id mismatch: expected 'test-task', got %v", taskID)
457		}
458	}
