460	// TestHarborRunnerImageNoHostPython verifies scripts/benchmark/harbor-runner/Dockerfile
461	// does not rely on host Python site-packages and build.sh only uses files under
462	// scripts/benchmark/harbor-runner/ and scripts/benchmark/harbor_adapters/.
463	func TestHarborRunnerImageNoHostPython(t *testing.T) {
464		repoRoot := getRepoRoot(t)
465		dockerfile := filepath.Join(repoRoot, "scripts", "benchmark", "harbor-runner", "Dockerfile")
466		buildScript := filepath.Join(repoRoot, "scripts", "benchmark", "harbor-runner", "build.sh")
467	
468		dockerfileData, err := os.ReadFile(dockerfile)
469		if err != nil {
470			t.Fatalf("Dockerfile not found: %v", err)
471		}
472	
473		dockerfileContent := string(dockerfileData)
474	
475		// Check that Dockerfile does not mount or copy host site-packages
476		hostPythonPatterns := []string{
477			"site-packages",
478			"/usr/local/lib/python",
479			"/usr/lib/python",
480		}
481	
482		for _, pattern := range hostPythonPatterns {
483			if strings.Contains(dockerfileContent, pattern) {
484				t.Errorf("Dockerfile contains reference to host Python: %s", pattern)
485			}
486		}
487	
488		// Check that Dockerfile doesn't do COPY from host Python locations
489		if strings.Contains(dockerfileContent, "COPY /") {
490			t.Errorf("Dockerfile uses absolute COPY paths which may reference host Python")
491		}
492	
493		// Verify build.sh only references appropriate paths
494		buildScriptData, err := os.ReadFile(buildScript)
495		if err != nil {
496			t.Fatalf("build.sh not found: %v", err)
497		}
498	
499		buildScriptContent := string(buildScriptData)
500	
501		// Check that all file references use controlled variables
502		lines := strings.Split(buildScriptContent, "\n")
503		for i, line := range lines {
504			trimmed := strings.TrimSpace(line)
505			if strings.HasPrefix(trimmed, "#") || trimmed == "" {
506				continue
507			}
508	
509			// Look for quoted file paths
510			if strings.Contains(trimmed, "\"${") || strings.Contains(trimmed, "'${") {
511				// Path uses variable, which is fine
512				continue
513			}
514	
515			// Check for absolute paths not in comments or strings
516			if strings.Contains(trimmed, "\"/") && !strings.Contains(trimmed, "DOCKER") {
517				// This might be an absolute path outside our controlled directories
518				// Allow REPO_ROOT usage which contains /
519				if !strings.Contains(trimmed, "REPO_ROOT") {
520					t.Logf("line %d may use uncontrolled absolute path: %s", i+1, trimmed)
521				}
522			}
523		}
524	
525		// Verify the adapters and agent paths are under harbor-runner parent and harbor_adapters
526		if !strings.Contains(buildScriptContent, "ADAPTERS_DIR") {
527			t.Errorf("build.sh missing ADAPTERS_DIR reference")
528		}
529		if !strings.Contains(buildScriptContent, "HARBOR_AGENT_PATH") {
530			t.Errorf("build.sh missing HARBOR_AGENT_PATH reference")
531		}
532	}
