534	// TestBenchmarkRunnerEndToEnd verifies a full cell execution: shell adapter → command-spec
535	// → task-executor → result.json → report.json. Uses docker-gated skip if unavailable.
536	func TestBenchmarkRunnerEndToEnd(t *testing.T) {
