538		benchmarkScript := filepath.Join(repoRoot, "scripts", "benchmark", "benchmark")
539		benchDir := filepath.Join(repoRoot, "scripts", "benchmark")
540	
541		if _, err := os.Stat(benchmarkScript); err != nil {
542			t.Fatalf("benchmark script not found: %v", err)
543		}
544	
545		// Check if docker is available
546		if _, err := exec.LookPath("docker"); err != nil {
547			t.Skip("docker not available")
548		}
549	
550		tmpDir := t.TempDir()
551	
552		// Use noop profile and a simple bench-set for end-to-end testing
