903		benchDir := filepath.Join(repoRoot, "scripts", "benchmark")
904	
905		if _, err := os.Stat(benchmarkScript); err != nil {
906			t.Fatalf("benchmark script not found: %v", err)
907		}
908	
909		if _, err := exec.LookPath("docker"); err != nil {
910			t.Skip("docker not available")
911		}
912	
913		tmpDir := t.TempDir()
914	
915		// Start a benchmark run with multiple cells
916		cmd := exec.Command(benchmarkScript,
917			"--profile", "noop",
918			"--bench-set", "tb-2-1-canary",
919			"--reps", "3",
920			"--jobs", "3",
921			"--out", tmpDir)
922		cmd.Dir = benchDir
923	
924		// Run in background so we can send signal
925		if err := cmd.Start(); err != nil {
926			t.Fatalf("failed to start benchmark: %v", err)
927		}
928	
929		// Give it a moment to start processing
930		select {
931		case <-time.After(500 * time.Millisecond):
932		}
933	
934		// Send SIGTERM
935		if err := cmd.Process.Signal(os.Interrupt); err != nil {
936			t.Logf("warning: failed to send signal: %v", err)
937		}
938	
939		// Wait with a timeout
940		done := make(chan error, 1)
941		go func() {
942			done <- cmd.Wait()
943		}()
944	
945		select {
946		case err := <-done:
947			// Exit code 130 indicates interrupted (SIGINT/SIGTERM)
948			if err != nil && !strings.Contains(err.Error(), "exit status") {
949				t.Logf("benchmark interrupted with error: %v (may be expected)", err)
950			}
951		case <-time.After(60 * time.Second):
952			t.Errorf("benchmark did not respond to SIGTERM within 60s")
953			cmd.Process.Kill()
954		}
