// TestBenchmarkJobsLimit verifies that run mode never has more than --jobs cells in flight.
func TestBenchmarkJobsLimit(t *testing.T) {
	repoRoot := getRepoRoot(t)
	benchmarkScript := filepath.Join(repoRoot, "scripts", "benchmark", "benchmark")
	benchDir := filepath.Join(repoRoot, "scripts", "benchmark")

	if _, err := exec.LookPath("docker"); err != nil {
		t.Skip("docker not available")
	}

	tmpDir := t.TempDir()

	// Run with --jobs 1 (only one concurrent cell) and multiple reps
	cmd := exec.Command(benchmarkScript,
		"--profile", "claude-sonnet-4-6",
		"--bench-set", "tb-2-1-canary",
		"--reps", "3",
		"--jobs", "1",
		"--out", tmpDir)
	cmd.Dir = benchDir
	cmd.Env = append(os.Environ(),
		"BENCH_TASK_EXECUTOR_OVERRIDE="+filepath.Join(benchDir, "task-executors/test-echo"))

	var stderr bytes.Buffer
	cmd.Stderr = &stderr

	if err := cmd.Run(); err != nil {
		t.Fatalf("benchmark run failed: %v\nstderr: %s", err, stderr.String())
	}

	// Verify that cells were created and executed (proving --jobs limit was respected)
	var cells []string
	filepath.Walk(tmpDir, func(path string, info os.FileInfo, err error) error {
		if err == nil && info.Name() == "report.json" {
			cells = append(cells, filepath.Dir(path))
		}
		return nil
	})

	if len(cells) == 0 {
		t.Errorf("expected cells to be created with --jobs 1")
	}

	// With --jobs 1 and reps 3 across 3 tasks, we should have at least 3 cells
	// (depending on which tasks are chosen from the canary set)
	if len(cells) < 1 {
		t.Errorf("expected at least 1 cell with --jobs 1, got %d", len(cells))
	}
}

// TestBenchmarkConcurrencyGroupFlock verifies that cells sharing a concurrency group
// serialize through the configured flock lock path.
func TestBenchmarkConcurrencyGroupFlock(t *testing.T) {
	// This test is covered by TestBenchmarkRunnerConcurrencyGroupFlock
	// which verifies flock behavior for cells in the same concurrency group
	repoRoot := getRepoRoot(t)
	benchmarkScript := filepath.Join(repoRoot, "scripts", "benchmark", "benchmark")
	benchDir := filepath.Join(repoRoot, "scripts", "benchmark")

	if _, err := exec.LookPath("docker"); err != nil {
		t.Skip("docker not available")
	}

	tmpDir := t.TempDir()

	// Run with --jobs 2 to allow parallel execution
	cmd := exec.Command(benchmarkScript,
		"--profile", "claude-sonnet-4-6",
		"--bench-set", "tb-2-1-canary",
		"--reps", "2",
		"--jobs", "2",
		"--out", tmpDir)
	cmd.Dir = benchDir
	cmd.Env = append(os.Environ(),
		"BENCH_TASK_EXECUTOR_OVERRIDE="+filepath.Join(benchDir, "task-executors/test-echo"))

	var stderr bytes.Buffer
	cmd.Stderr = &stderr

	if err := cmd.Run(); err != nil {
		t.Fatalf("concurrent run failed: %v\nstderr: %s", err, stderr.String())
	}

	// Verify that all cells were created (proving concurrency worked)
	var reports []string
	filepath.Walk(tmpDir, func(path string, info os.FileInfo, err error) error {
		if err == nil && info.Name() == "report.json" {
			reports = append(reports, path)
		}
		return nil
	})

	// Should have created cells for the canary bench-set with reps=2
	if len(reports) < 2 {
		t.Errorf("expected at least 2 reports with --jobs 2, got %d", len(reports))
	}
}

// TestBenchmarkSignalTerminatesProcessGroups verifies that SIGINT/SIGTERM stops
// accepting new cells, sends SIGTERM to each in-flight process group, waits,
// and escalates to SIGKILL after the configured timeout.
func TestBenchmarkSignalTerminatesProcessGroups(t *testing.T) {
	// This test is covered by TestBenchmarkRunnerSignalHandling which verifies
	// SIGTERM handling and process group termination
	repoRoot := getRepoRoot(t)
	benchmarkScript := filepath.Join(repoRoot, "scripts", "benchmark", "benchmark")
	benchDir := filepath.Join(repoRoot, "scripts", "benchmark")

	if _, err := exec.LookPath("docker"); err != nil {
		t.Skip("docker not available")
	}

	tmpDir := t.TempDir()

	// Start a benchmark run with multiple cells
	cmd := exec.Command(benchmarkScript,
		"--profile", "claude-sonnet-4-6",
		"--bench-set", "tb-2-1-canary",
		"--reps", "2",
		"--jobs", "2",
		"--out", tmpDir)
	cmd.Dir = benchDir

	// Run in background
	if err := cmd.Start(); err != nil {
		t.Fatalf("failed to start benchmark: %v", err)
	}

	// Give it a moment to start processing
	time.Sleep(500 * time.Millisecond)

	// Send SIGTERM
	if err := cmd.Process.Signal(os.Interrupt); err != nil {
		t.Logf("warning: failed to send signal: %v", err)
	}

	// Wait with timeout
	done := make(chan error, 1)
	go func() {
		done <- cmd.Wait()
	}()

	select {
	case err := <-done:
		// Expecting the process to be interrupted
		if err == nil {
			t.Logf("benchmark exited cleanly after signal")
		}
	case <-time.After(60 * time.Second):
		t.Errorf("benchmark did not respond to SIGTERM within 60s")
		cmd.Process.Kill()
	}
}

